function calculateDimensions(){$("#viewport-width-sb").text(window.innerWidth+" px"),$("#viewport-height-sb").text(window.innerHeight+" px"),$("#viewport-width").text(document.documentElement.clientWidth+" px"),$("#viewport-height").text(document.documentElement.clientHeight+" px"),$("#window-width").text(window.outerWidth+" px"),$("#window-height").text(window.outerHeight+" px"),$("#screen-width").text(screen.width+" px"),$("#screen-height").text(screen.height+" px"),$("#screen-availwidth").text(screen.availWidth+" px"),$("#screen-availheight").text(screen.availHeight+" px"),$("#color-depth").text(screen.colorDepth),$("#pixel-depth").text(screen.pixelDepth)}function jsReload(){location.reload()}function jsCopy(e){var t=document.getElementById(e);t.select(),t.setSelectionRange(0,99999),document.execCommand("copy")}function scrollFunction(){document.body.scrollTop>20||document.documentElement.scrollTop>20?document.getElementById("my-btn").style.display="block":document.getElementById("my-btn").style.display="none"}function topFunction(){document.body.scrollTop=0,document.documentElement.scrollTop=0}function openNav(){document.getElementById("my-side-nav").style.width="190px"}function closeNav(){document.getElementById("my-side-nav").style.width="0"}calculateDimensions(),window.addEventListener("resize",calculateDimensions),window.onscroll=function(){scrollFunction()};